package pe.edu.utp.tmo.infrastructure.persistence; import java.util.Optional; import org.springframework.stereotype.Repository; import pe.edu.utp.tmo.dao.SlaDAO; import pe.edu.utp.tmo.infrastructure.persistence.repository.ParametroSLARepository; import pe.edu.utp.tmo.model.entity.ParametroSLA; import pe.edu.utp.tmo.model.enums.TipoCaso; @Repository public class SlaJpaDAO implements SlaDAO{ private final ParametroSLARepository r; public SlaJpaDAO(ParametroSLARepository r){this.r=r;} public Optional<ParametroSLA> buscarPorTipoCaso(TipoCaso t){return r.findFirstByTipoCasoAndActivoTrue(t);} public ParametroSLA guardarParametro(ParametroSLA p){return r.save(p);} }